class Solution {
public:
    int findMaxK(vector<int>& nums) {
        set<int> pos;
        for (int num : nums) {
            pos.insert(num);
        }
        for (int num : nums) {
            if (pos.count(-num)) {
                return abs(num);
            }
        }
        return -1;
    }
};
